#include<iostream>
#include<vector>
using namespace std;


bool is_prime(long long x){
    if(x <= 1) return false;
    if(x <= 2) return true;
    if(x % 2 == 0) return false;
    for(long long i = 3; i * i <= x; i += 2){
        if(x % i == 0) return false;
    }
    return true;
}

int main(){
    long long n,k,atleast;
    cin >> n >> k >> atleast;
    long long p;
    int cnt = 0;
    for(int i=0;i<n;i++){
        cin >> p;
        if((1+cnt*k) * (1+cnt*k) == p){
            cnt++;
            continue;
        }
        if(is_prime(p)){
            continue;
        }
        cout << "Wrong!" << endl << i+1;
        return 0;
    }
    if(cnt >= atleast){
        cout << "It's MyGO!!!!!" << endl;
    }else{
        cout << "Useless!" << endl;
    }
}
